--- c2s

---@param formationObj LxFormationObj
function LxBattleHandler:_ConvertFormationObjToPb(formationObj, targetPb, battleType)
    targetPb.formationType = formationObj.formationType
    targetPb.order = formationObj.order
    targetPb.formationRefId = formationObj.formationRefId or 1

    local positions = formationObj.positions
    local pbGrids = targetPb.grids
    for i = 1, BattlePosCount do
        local unit = positions[i]
        if unit then
            local pbUnit = pbGrids:add()
            pbUnit.id = unit.id
            pbUnit.grid = unit.index
        end
    end
end

--- 战斗请求
---@param battleType number 战斗类型 与指定玩家战斗(99999)
---@param params string json格式参数(各个模块战斗自定义)
function LxBattleHandler:CombatReq(battleType, params)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CombatReq)
    proto.combatType = battleType
    if params then
        local atkFormation = params.atkFormation
        if atkFormation then
            self:_ConvertFormationObjToPb(atkFormation, proto.atkFormation, battleType)
        end
        local defFormation = params.defFormation
        if defFormation then
            self:_ConvertFormationObjToPb(defFormation, proto.defFormation, battleType)
        end
        local relFormation = params.relFormation
        if relFormation then
            self:_ConvertFormationObjToPb(relFormation, proto.relFormation, battleType)
        end
        local targetId = params.targetId
        if targetId then
            proto.targetId = targetId
        end
        local jParameter = params.jParameter
        if jParameter then
            proto.jParameter = jParameter
        end
    end
    SendMessage(LxProtoIds.CombatReq, proto)
end


function LxBattleHandler:OnCombatResultReq(reportId, battleType, cancel)
    cancel = cancel and 1 or 0
    local pb = LxProtoHelper.CreateProto(LxProtoIds.CombatResultReq)
    pb.reportId = reportId
    pb.cancel = cancel
    pb.combatType = battleType
    SendMessage(LxProtoIds.CombatResultReq, pb)
end

--- 布阵
---@param formationType number 阵型类型
---@param attackFormations table<LxFormationObj>
---@param defendFormations table<LxFormationObj>
function LxBattleHandler:SetFormationReq(formationType, attackFormations, defendFormations, reqIndex, formationSetType)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.SetFormationReq)
    proto.combatType = formationType
    if attackFormations then
        for k,v in ipairs(attackFormations) do
            local pbAtkFormation = proto.attackFormations:add()
            self:_ConvertFormationObjToPb(v, pbAtkFormation, formationType)
        end
    end
    if defendFormations then
        for k,v in ipairs(defendFormations) do
            local pbDefendFormation = proto.defendFormations:add()
            self:_ConvertFormationObjToPb(v, pbDefendFormation, formationType)
        end
    end
    if formationSetType then
        proto.formationSetType = formationSetType
    end
    if reqIndex then
        proto.reqIndex = reqIndex
    end
    SendMessage(LxProtoIds.SetFormationReq, proto)
end


--查看目标布阵
function LxBattleHandler:ViewTargetFormationReq(type,roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.ViewTargetFormationReq)
    proto.type = type
    proto.roleId = roleId
    SendMessage(LxProtoIds.ViewTargetFormationReq, proto)
end
