function LxBattleHandler:OnSetFormationResp(pb)
    local type = self:SetFormationData(pb)
    if pb.formationSetType == 0 then
        CtrlCenter.Battle:OnSaveFormationFinish(type, pb.reqIndex)
    end
    CtrlCenter.Story:Formationed()
end

function LxBattleHandler:OnFormationDataResp(pb)
    if not pb then return end
    for i,v in ipairs(pb.groups) do
        self:SetFormationData(v)
    end
end

function LxBattleHandler:OnApplyFormationResp(pb)
    if not pb then return end
    for i,v in ipairs(pb.groups) do
        self:SetFormationData(v)
    end
end

function LxBattleHandler:OnRenameFormationResp(pb)
    if not pb then return end
    for i,v in ipairs(pb.groups) do
        self:SetFormationData(v)
    end
end

function LxBattleHandler:OnViewTargetFormationResp(pb)
    ModuleCenter.Arena:SetTargetFormation(pb)
    FireEvent(EventNames.REFRESH_ARENA_VIEWFORMATION)
end

function LxBattleHandler:SetFormationData(pb)
    local type = pb.combatType
    local attackFormations = pb.attackFormations
    local defendFormations = pb.defendFormations
    for i, formationPb in ipairs(attackFormations) do
        local order = formationPb.order
        ---@type LxFormationObj
        local formation = ModuleCenter.Battle:GetFormation(type, order)
        if not formation then
            formation = ModuleCenter.Battle:NewFormation()
            formation:SetPbData(formationPb)
            ModuleCenter.Battle:AddFormation(type, formation)
        else
            formation:SetPbData(formationPb)
        end
    end
    for i, formationPb in ipairs(defendFormations) do
        local order = formationPb.order
        ---@type LxFormationObj
        local formation = ModuleCenter.Battle:GetFormation(type, order, true)
        if not formation then
            formation = ModuleCenter.Battle:NewFormation()
            formation:SetPbData(formationPb)
            ModuleCenter.Battle:AddFormation(type, formation, true)
        else
            formation:SetPbData(formationPb)
        end
    end
    return type
end

return LxBattleHandler